package main; import ("encoding/json"; "log"; "os"; "nwork/internal/config"; "nwork/internal/database"; "nwork/internal/models"; "gorm.io/gorm"); func main() { if err := config.LoadConfig(); err != nil { log.Fatalf("❌ Failed to load .env config: %v", err) }; if err := database.InitDB(); err != nil { log.Fatalf("❌ Failed to connect to database: %v", err) }; db := database.DB; var tenant models.Tenant; log.Println(">>> Finding first active tenant..."); err := db.Where("status = ?", "active").First(&tenant).Error; if err != nil { if err == gorm.ErrRecordNotFound { log.Fatalf("❌ No active tenant found in the database.") }; log.Fatalf("❌ Failed to query for tenant: %v", err) }; log.Printf("   Found tenant: %s (ID: %s)", tenant.Name, tenant.ID); if tenant.ExtraFields == nil { tenant.ExtraFields = make(models.JSONB) }; const devDomain = "localhost:3001"; var domains []string; if rawDomains, ok := tenant.ExtraFields["website_custom_domains"]; ok { domainsBytes, err := json.Marshal(rawDomains); if err == nil { _ = json.Unmarshal(domainsBytes, &domains) } }; domainExists := false; for _, domain := range domains { if domain == devDomain { domainExists = true; break } }; if domainExists { log.Printf("[OK] %s already exists for tenant %s.", devDomain, tenant.Name); os.Exit(0) }; log.Printf(">>> Adding %s to custom domains...", devDomain); domains = append(domains, devDomain); tenant.ExtraFields["website_custom_domains"] = domains; if err := db.Save(&tenant).Error; err != nil { log.Fatalf("❌ Failed to save updated tenant: %v", err) }; log.Printf("✅ Successfully added %s for tenant %s.", devDomain, tenant.Name) }
